SELECT STRFTIME('%Y-%m-%d %H:%M:%S', MAX(rating_date)) AS latest_rated_date
FROM show_ratings
WHERE rating_value = 8.0 AND source = 'critic';

SELECT COUNT(*) AS total_shows
FROM shows 
WHERE rating > (SELECT AVG(rating) FROM shows);

SELECT AVG(rating) AS average_rating
FROM shows
WHERE rating = (
  SELECT MAX(rating)
  FROM shows
);

SELECT AVG(rating) AS average_rating, total_views
FROM shows
WHERE total_views = (SELECT MAX(total_views) FROM shows);
